SELECT * FROM client_file
WHERE matter_id = #{matterId}
AND deleted = false

    AND status = #{status}

ORDER BY uploaded_at DESC

SELECT * FROM client_file
WHERE id = #{externalFileId}
AND deleted = false

SELECT * FROM client_file
WHERE deleted = false

    AND matter_id = #{matterId}


    AND status = #{status}


    AND file_category = #{fileCategory}


    AND (file_name ILIKE CONCAT('%', #{keyword}, '%') 
         OR description ILIKE CONCAT('%', #{keyword}, '%'))

ORDER BY uploaded_at DESC
LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*) FROM client_file
WHERE deleted = false

    AND matter_id = #{matterId}


    AND status = #{status}


    AND file_category = #{fileCategory}


    AND (file_name ILIKE CONCAT('%', #{keyword}, '%') 
         OR description ILIKE CONCAT('%', #{keyword}, '%'))

SELECT COALESCE(SUM(file_size), 0) FROM client_file
WHERE deleted = false

    AND status = #{status}

SELECT COUNT(*) FROM client_file
WHERE deleted = false
AND file_category = #{fileCategory}
